  "gold_actions": {
    "global": "Derive the Maxwell relation (вҲӮS/вҲӮp)_T = -(вҲӮE/вҲӮT)_p from the Carnot cycle, substitute E = PT/(nKОөвӮҖ) from Curie law, show (вҲӮU/вҲӮp)_T = 0, and conclude U(T,P) = CT.",
    "subtasks": [
      {
        "subtask": "Derive the Maxwell relation from the Carnot cycle / Helmholtz free energy",
        "atomics": [
          "Write F = U - TS, dF = -SdT + Edp",
          "Apply вҲӮВІF/вҲӮTвҲӮp = вҲӮВІF/вҲӮpвҲӮT to obtain (вҲӮS/вҲӮp)_T = -(вҲӮE/вҲӮT)_p",
